const LOGO_BASE64 = ''

export function cabecalhoImpressao() {
  return `
    <div style="display:flex;align-items:center;gap:14px;border-bottom:2px solid #1e6b2e;padding-bottom:8px;margin-bottom:12px;">
      <img src="data:image/jpeg;base64,${LOGO_BASE64}" style="height:70px;width:auto;" alt="Logo SMS">
      <div>
        <p style="font-weight:700;font-size:13px;text-transform:uppercase;margin:0 0 2px;">Prefeitura Municipal de Conceição do Tocantins</p>
        <p style="font-weight:700;font-size:13px;text-transform:uppercase;margin:0 0 2px;">Secretaria Municipal de Saúde</p>
        <p style="font-weight:700;font-size:13px;text-transform:uppercase;margin:0;">Fundo Municipal de Saúde</p>
      </div>
    </div>
  `
}

export function estilosImpressao() {
  return `
    body { font-family: Arial, sans-serif; font-size: 11px; padding: 10px; color: #000; }
    table { width: 100%; border-collapse: collapse; margin-bottom: 8px; table-layout: fixed; }
    th, td { border: 1px solid #000; padding: 3px 5px; vertical-align: middle; word-wrap: break-word; white-space: normal; }
    th { background: #eaeaea; text-transform: uppercase; font-size: 10px; text-align: center; }
    @page { size: A4 landscape; margin: 8mm; }
  `
}

export function abrirJanelaImpressao(titulo, conteudo) {
  const janela = window.open('', '_blank')
  janela.document.open()
  janela.document.write(`<!doctype html><html><head><meta charset="utf-8"><title>${titulo}</title><style>${estilosImpressao()}</style></head><body>${cabecalhoImpressao()}${conteudo}</body></html>`)
  janela.document.close()
  setTimeout(() => janela.print(), 300)
}

export function cabecalhoComTituloDireito(linhaDir1, linhaDir2) {
  return `
    <div style="display:flex;align-items:center;justify-content:space-between;border-bottom:2px solid #1e6b2e;padding-bottom:8px;margin-bottom:12px;">
      <div style="display:flex;align-items:center;gap:14px;">
        <img src="data:image/jpeg;base64,${LOGO_BASE64}" style="height:70px;width:auto;" alt="Logo SMS">
        <div>
          <p style="font-weight:700;font-size:13px;text-transform:uppercase;margin:0 0 2px;">Prefeitura Municipal de Conceição do Tocantins</p>
          <p style="font-weight:700;font-size:13px;text-transform:uppercase;margin:0 0 2px;">Fundo Municipal de Saúde</p>
                    <p style="font-weight:700;font-size:13px;text-transform:uppercase;margin:0 0 2px;">Secretaria Municipal de Saúde</p>
        </div>
      </div>
      <div style="text-align:right;">
        <p style="font-weight:700;font-size:12px;text-transform:uppercase;margin:0 0 2px;">${linhaDir1}</p>
        ${linhaDir2 ? `<p style="font-weight:700;font-size:11px;text-transform:uppercase;margin:0;">${linhaDir2}</p>` : ''}
      </div>
    </div>
  `
}

export function abrirJanelaImpressaoComTitulo(titulo, linhaDir1, linhaDir2, conteudo) {
  const janela = window.open('', '_blank')
  janela.document.open()
  janela.document.write(`<!doctype html><html><head><meta charset="utf-8"><title>${titulo}</title><style>${estilosImpressao()}</style></head><body>${cabecalhoComTituloDireito(linhaDir1, linhaDir2)}${conteudo}</body></html>`)
  janela.document.close()
  setTimeout(() => janela.print(), 300)
}